export interface BrowserStorage {
  getItem(key: string): string | null;
  setItem(key: string, value: string): void;
}

export interface BrowserRuntime {
  baseUrl: string;
  fetch: typeof globalThis.fetch;
  WebSocket: typeof globalThis.WebSocket;
  storage?: BrowserStorage;
}

interface ClientRegistrationResponse {
  clientId: string;
  config?: {
    httpBaseUrl?: string;
    realtimePath?: string;
  };
}

interface BackendErrorResponse {
  error?: string;
}

export interface ParsedCommandResponse {
  name: string;
  arguments: string[];
  raw?: string;
}

export interface ExecuteCommandOptions {
  input: string;
  userId?: string;
  username?: string;
}

export interface ExecuteCommandResponse {
  result: unknown;
  replies: unknown[];
  deprecated?: Record<string, string>;
}

export interface RealtimeEnvelope<TPayload = unknown> {
  type: string;
  payload: TPayload;
  id?: string;
}

export interface ZenithraClientHooks {
  onRegistered?(client: ZenithraClient): void;
  onOpen?(client: ZenithraClient): void;
  onClose?(client: ZenithraClient): void;
  onMessage?(message: RealtimeEnvelope, client: ZenithraClient): void;
  onError?(error: unknown, client: ZenithraClient): void;
}

const CLIENT_ID_STORAGE_KEY = "zenithra.clientId";
const HEARTBEAT_INTERVAL_MS = 30_000;
const RECONNECT_DELAY_MS = 1_500;

const normalizeBaseUrl = (value: string): string => value.replace(/\/+$/u, "");

const isObjectRecord = (value: unknown): value is Record<string, unknown> =>
  typeof value === "object" && value !== null && !Array.isArray(value);

export const toWsUrl = (httpUrl: string): string =>
  httpUrl.replace(/^http:\/\//u, "ws://").replace(/^https:\/\//u, "wss://");

export class ZenithraClient {
  private clientId: string | null;
  private socket: WebSocket | null = null;
  private heartbeat: number | undefined;
  private reconnectTimer: number | undefined;
  private httpBaseUrl: string;

  constructor(
    private readonly runtime: BrowserRuntime,
    private readonly hooks: ZenithraClientHooks = {}
  ) {
    this.clientId = this.runtime.storage?.getItem(CLIENT_ID_STORAGE_KEY) ?? null;
    this.httpBaseUrl = normalizeBaseUrl(runtime.baseUrl);
  }

  get registeredClientId(): string | null {
    return this.clientId;
  }

  get baseUrl(): string {
    return this.httpBaseUrl;
  }

  async start(): Promise<void> {
    const registration = await this.register();
    this.clientId = registration.clientId;
    this.httpBaseUrl = normalizeBaseUrl(registration.config?.httpBaseUrl ?? this.runtime.baseUrl);
    this.runtime.storage?.setItem(CLIENT_ID_STORAGE_KEY, registration.clientId);
    this.hooks.onRegistered?.(this);
    this.connect(registration);
  }

  async parseCommand(input: string): Promise<ParsedCommandResponse> {
    return this.requestJson<ParsedCommandResponse>("/command/parse", {
      method: "POST",
      body: {
        input
      }
    });
  }

  async executeCommand(options: ExecuteCommandOptions): Promise<ExecuteCommandResponse> {
    return this.requestJson<ExecuteCommandResponse>("/command/execute", {
      method: "POST",
      body: {
        input: options.input,
        userId: options.userId ?? this.clientId ?? "0",
        username: options.username ?? "Drednot_User"
      }
    });
  }

  sendRealtime<TPayload>(message: RealtimeEnvelope<TPayload>): void {
    if (this.socket?.readyState !== this.runtime.WebSocket.OPEN) return;
    this.socket.send(JSON.stringify(message));
  }

  private async register(): Promise<ClientRegistrationResponse> {
    return this.requestJson<ClientRegistrationResponse>("/client/register", {
      method: "POST",
      body: this.clientId === null ? {} : { clientId: this.clientId }
    });
  }

  private async requestJson<TResponse>(
    pathname: string,
    options: {
      method: "GET" | "POST";
      body?: Record<string, unknown>;
    }
  ): Promise<TResponse> {
    const response = await this.runtime.fetch(new URL(pathname, `${this.httpBaseUrl}/`), {
      method: options.method,
      headers: {
        "Content-Type": "application/json"
      },
      ...(options.body === undefined ? {} : { body: JSON.stringify(options.body) })
    });

    const payload = await response.json() as TResponse | BackendErrorResponse;

    if (!response.ok) {
      throw new Error(
        isObjectRecord(payload) && typeof payload.error === "string"
          ? payload.error
          : `Request failed with status ${String(response.status)}.`
      );
    }

    return payload as TResponse;
  }

  private connect(registration: ClientRegistrationResponse): void {
    this.clearReconnectTimer();
    this.clearHeartbeat();

    const realtimePath = registration.config?.realtimePath ?? "/realtime";
    const socketUrl = new URL(realtimePath, `${toWsUrl(this.httpBaseUrl)}/`);

    const socket = new this.runtime.WebSocket(socketUrl.toString());
    this.socket = socket;

    socket.addEventListener("open", () => {
      this.sendRealtime({
        type: "client.register",
        payload: {
          clientId: registration.clientId
        }
      });

      this.heartbeat = globalThis.setInterval(() => {
        this.sendRealtime({
          type: "heartbeat.ping",
          payload: {
            timestamp: Date.now()
          }
        });
      }, HEARTBEAT_INTERVAL_MS);

      this.hooks.onOpen?.(this);
    });

    socket.addEventListener("message", (event) => {
      this.handleMessage(event.data);
    });

    socket.addEventListener("close", () => {
      this.socket = null;
      this.clearHeartbeat();
      this.hooks.onClose?.(this);
      this.scheduleReconnect();
    });
  }

  private handleMessage(data: unknown): void {
    if (typeof data !== "string") return;

    const message = JSON.parse(data) as RealtimeEnvelope;
    if (message.type === "error") {
      this.hooks.onError?.(message.payload, this);
      console.error("[ZenithraClient]", message.payload);
      return;
    }

    this.hooks.onMessage?.(message, this);
  }

  private scheduleReconnect(): void {
    if (this.reconnectTimer !== undefined) return;

    this.reconnectTimer = globalThis.setTimeout(() => {
      this.reconnectTimer = undefined;
      void this.start().catch((error: unknown) => {
        this.hooks.onError?.(error, this);
        console.error("[ZenithraClient]", error);
        this.scheduleReconnect();
      });
    }, RECONNECT_DELAY_MS);
  }

  private clearHeartbeat(): void {
    if (this.heartbeat === undefined) return;
    globalThis.clearInterval(this.heartbeat);
    this.heartbeat = undefined;
  }

  private clearReconnectTimer(): void {
    if (this.reconnectTimer === undefined) return;
    globalThis.clearTimeout(this.reconnectTimer);
    this.reconnectTimer = undefined;
  }
}

export const startZenithraClient = async (
  runtime: BrowserRuntime,
  hooks?: ZenithraClientHooks
): Promise<ZenithraClient> => {
  const client = new ZenithraClient(runtime, hooks);
  await client.start();
  return client;
};
